//                                                                                 ||//                         بِسْمِ ٱللّٰهِ ٱلرَّحْمٰنِ ٱلرَّحِيمِ                                       ||// "وَلَقَدْ خَلَقْنَا الْإِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِ نَفْسُهُ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ" (Quran 50:16) -     ||//                                                                                 ||#include <bits/stdc++.h>using namespace std;int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--) {        int n;    cin >> n;    vector<int> b(n);    for (int i = 0; i < n; i++) {        cin >> b[i];    }    vector<int> a;    a.push_back(b[0]);    for (int i = 1; i < n; i++) {        if (b[i-1] > b[i]) {            a.push_back(b[i]);        }        a.push_back(b[i]);    }    cout << a.size() << "\n";    for (int i = 0; i < a.size(); i++) {        cout << a[i] << (i == a.size() - 1 ? "" : " ");    }    cout << "\n";    }    return 0;}